module edge_detector (
	input clk,
	input rst,
	input d,
	output reg edge_detected);

	reg d_last;

	always @(posedge clk) begin
		if (rst)
			d_last <= 0;
		else
			d_last <= d;
	end

	always @(posedge clk) begin
		if (rst)
			edge_detected <= 0;
		else
			edge_detected <= d & ~d_last;
	end

endmodule
